import json

# Debug: Check what variables are available
vars_dict = {}
for key in locals().keys():
    if key.startswith('var_'):
        vars_dict[key] = type(locals()[key]).__name__

print('Available variables:', list(vars_dict.keys()))

# Get the cases from the query results
cases_data = None
for key, value in locals().items():
    if key.startswith('var_') and isinstance(value, list) and len(value) > 0:
        if isinstance(value[0], dict) and 'id' in value[0] and 'accountid' in value[0]:
            cases_data = value
            break

if cases_data:
    # Extract unique account IDs
    account_ids = set()
    for case in cases_data:
        account_id = case.get('accountid', '')
        if account_id:
            # Remove leading # if present
            if account_id.startswith('#'):
                account_id = account_id[1:]
            account_ids.add(account_id)

    print(f"Number of cases: {len(cases_data)}")
    print(f"Number of unique accounts: {len(account_ids)}")

    # Format IDs for SQL query
    id_list = "('" + "','".join(list(account_ids)) + "')" if account_ids else "('')"

    print('__RESULT__:')
    print(json.dumps(id_list))
else:
    print('No cases data found')

